mapper.update:
UPDATE tb_salary SET
    addition_amount  = #{additionAmount},
    deduction_amount = #{deductionAmount},
    payable_amount   = #{payableAmount}
WHERE id = #{id}

mapper.delete:
DELETE FROM tb_salary
WHERE project_id = #{projectId}
  AND salary_period = #{salaryPeriod}

mapper.select:
SELECT s.*, e.name AS employee_name, jc.name AS job_category_name FROM tb_salary s LEFT JOIN tb_employee e ON s.employee_id = e.id LEFT JOIN tb_job_category jc ON e.job_category_id = jc.id WHERE 1=1
AND s.employee_id = #{employeeId}
AND s.salary_period = #{salaryPeriod}
AND s.project_id = #{projectId}
ORDER BY s.salary_period DESC, e.name ASC

SELECT s.*, e.name AS employee_name
FROM tb_salary s
LEFT JOIN tb_employee e ON s.employee_id = e.id
WHERE s.employee_id = #{employeeId}
  AND s.salary_period = #{salaryPeriod}
  AND s.project_id = #{projectId}
